+/// Core prompt structure
+#[derive(Debug, Clone, Serialize, Deserialize)]
+pub struct Prompt {
+    pub id: String,
+    pub title: String,
+    pub content: String,
+    #[serde(default)]
+    pub description: Option<String>,
+    #[serde(default)]
+    pub category: Option<String>,
+    #[serde(default)]
+    pub tags: Vec<String>,
+    #[serde(default)]
+    pub variables: Vec<PromptVariable>,
+    #[serde(default)]
+    pub featured: bool,
+    #[serde(default)]
+    pub version: Option<String>,
+    #[serde(default)]
+    pub author: Option<String>,
+    /// For synced/saved prompts
+    #[serde(default)]
+    pub saved_at: Option<String>,
+    /// Local prompt indicator
+    #[serde(default)]
+    pub is_local: bool,
+}
+
+impl Prompt {
+    /// Create a new prompt with required fields
+    pub fn new(id: impl Into<String>, title: impl Into<String>, content: impl Into<String>) -> Self {
+        Self {
+            id: id.into(),
+            title: title.into(),
+            content: content.into(),
+            description: None,
+            category: None,
+            tags: Vec::new(),
+            variables: Vec::new(),
+            featured: false,
+            version: None,
+            author: None,
+            saved_at: None,
+            is_local: false,
+        }
+    }
+
+    /// Get content preview (first N lines)
+    pub fn preview(&self, lines: usize) -> String {
+        self.content
+            .lines()
+            .take(lines)
+            .collect::<Vec<_>>()
+            .join("\n")
+    }
+
+    /// Check if prompt matches a category filter
+    pub fn matches_category(&self, category: &str) -> bool {
+        self.category
+            .as_ref()
+            .is_some_and(|c| c.eq_ignore_ascii_case(category))
+    }
+
+    /// Check if prompt has a specific tag
+    pub fn has_tag(&self, tag: &str) -> bool {
+        self.tags.iter().any(|t| t.eq_ignore_ascii_case(tag))
+    }
+}
+
+/// Summary view of a prompt for list output
